    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    using namespace sqlgen::literals;

    // 1. Establish database connection
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // 2. Create standard index on category with IF NOT EXISTS
    auto category_index = sqlgen::create_index<"idx_product_category", Product>("category"_c);
    auto category_index_with_flag = category_index | sqlgen::if_not_exists;
    if (!category_index_with_flag(conn)) {
      return false;
    }

    // 3. Create unique index on sku with IF NOT EXISTS
    auto sku_index = sqlgen::create_index<"idx_product_sku", Product>("sku"_c);
    sku_index.unique_ = true;  // Set unique flag
    auto sku_index_with_flag = sku_index | sqlgen::if_not_exists;
    if (!sku_index_with_flag(conn)) {
