```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // Check if User table exists by attempting to read from it
  auto read_result = conn.read<std::vector<User>>();
  if (!read_result) {
    return false; // Table doesn't exist or read failed
  }

  // Generate and execute ALTER TABLE statements using sqlgen functions
  // Add phone_number column
  auto alter1_result = conn.execute(
      "ALTER TABLE User ADD COLUMN phone_number VARCHAR(20)"
  );
  if (!alter1_result) {
    return false; // First ALTER TABLE failed
  }

  // Add is_active column with default value
  auto alter2_result = conn.execute(
      "ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1"
  );
  if (!alter2_result) {
    return false; // Second ALTER TABLE failed
  }

  return true; // Migration completed successfully
}

} // namespace schema_migration_add_column
```

