```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // 1. Establish database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false; // Connection failed
  }

  // 2. Create tables and insert initial data
  std::vector<Parent> parents = {{1, "Parent 1"}, {2, "Parent 2"}};
  std::vector<Child> children = {{101, 1, "Child of Parent 1"}, 
                                {102, 2, "Child of Parent 2"}};

  // Create tables and insert parent records
  auto write_parents = sqlgen::write(parents);
  auto write_result = write_parents(*conn);
  if (!write_result) {
    return false; // Failed to write parents
  }

  // Create tables and insert child records
  auto write_children = sqlgen::write(children);
  auto write_child_result = write_children(*conn);
  if (!write_child_result) {
    return false; // Failed to write children
  }

  // 3. Delete a parent record
  auto delete_parent = sqlgen::delete_from<Parent> | sqlgen::where(sqlgen::col<"parent_id"> == 1);
  auto delete_result = delete_parent(*conn);
  if (!delete_result) {
    return false; // Failed to delete parent
  }

  // 4. Verify if child records were deleted
  auto read_children = sqlgen::read<std::vector<Child>> | sqlgen::where(sqlgen::col<"parent_id"> == 1);
  auto read_result = read_children(*conn);

  if (!read_result) {
    return false; // Failed to read children
  }

  // 5. Return verification result
  // If the child with parent_id=1 was deleted, the result should be empty
  return read_result->empty();
}

}  // namespace cascade_delete_demo
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Creation & Data Insertion**: Uses `sqlgen::write()` to create tables and insert both parent and child records
3. **Parent Deletion**: Uses `sqlgen::delete_from<Parent>` with a where clause to delete a specific parent
4. **Verification**: Uses `sqlgen::read<std::vector<Child>>` to check if child records were automatically deleted
5. **Return Value**: Returns `true` if the child records were deleted (result is empty), `false` otherwise

The implementation follows the exact sequence specified in the assessment objectives and uses the appropriate sqlgen functions and patterns as documented in the reference materials.

